code = """import json

# Get the direct references using locals() to handle colon-containing variable names
lit_fiction_key = None
perfect_ratings_key = None

# Find the correct variable names from all available variables
for key in dir():
    if 'query_db' in key and '50' in str(key):
        lit_fiction_key = key
    if 'query_db' in key and '32' in str(key):
        perfect_ratings_key = key

print(f"Found keys: lit_fiction={lit_fiction_key}, perfect_ratings={perfect_ratings_key}")

# Get the data using locals()
if lit_fiction_key and perfect_ratings_key:
    lit_fiction_books = locals()[lit_fiction_key]
    perfect_ratings_data = locals()[perfect_ratings_key]
    
    print(f"Literature & Fiction books: {len(lit_fiction_books)}")
    print(f"Perfect ratings count: {len(perfect_ratings_data)}")
    
    # Create set of purchase_ids with perfect ratings
    perfect_purchase_ids = {item['purchase_id'] for item in perfect_ratings_data}
    
    # Map bookid_x to purchaseid_x and check for matches
    matching_books = []
    
    for book in lit_fiction_books:
        book_id = book['book_id']
        if book_id.startswith('bookid_'):
            num = book_id.split('_')[1]
            purchase_id = f'purchaseid_{num}'
            
            if purchase_id in perfect_purchase_ids:
                # Get rating info
                rating_info = next((r for r in perfect_ratings_data if r['purchase_id'] == purchase_id), None)
                if rating_info:
                    matching_books.append({
                        'title': book['title'],
                        'book_id': book_id,
                        'purchase_id': purchase_id,
                        'avg_rating': float(rating_info['avg_rating']),
                        'review_count': int(rating_info['review_count']),
                        'categories': book['categories']
                    })
    
    print(f"Found {len(matching_books)} matching books")
    
    # Display results
    result = {
        'total_books': len(matching_books),
        'books': matching_books
    }
    
    print('__RESULT__:')
    print(json.dumps(result, indent=2))
else:
    print("Could not find required data")
    result = {'error': 'Missing data'}
    print('__RESULT__:')
    print(json.dumps(result))"""

